declare @name nvarchar(4000), @header nvarchar(512)
select @header =
  case
    when @bc_theo = 1 then case when @@language = 'V' then N'Tài khoản' else 'Account' end
    when @bc_theo = 2 then case when @@language = 'V' then N'Phí' else 'Expense' end
    when @bc_theo = 3 then case when @@language = 'V' then N'Đơn vị cơ sở' else 'Unit' end
    when @bc_theo = 4 then case when @@language = 'V' then N'Bộ phận' else 'Department' end
    when @bc_theo = 5 then case when @@language = 'V' then N'Vụ việc' else 'Job' end
  end
select @name =
  case
    when @bc_theo = 1 then (select case when @@language = 'V' then ten_tk else ten_tk2 end from dmtk where tk = @ma)
    when @bc_theo = 2 then (select case when @@language = 'V' then ten_phi else ten_phi2 end from dmphi where ma_phi = @ma)
    when @bc_theo = 3 then (select case when @@language = 'V' then ten_dvcs else ten_dvcs2 end from dmdvcs where ma_dvcs = @ma)
    when @bc_theo = 4 then (select case when @@language = 'V' then ten_bp else ten_bp2 end from dmbp where ma_bp = @ma)
    when @bc_theo = 5 then (select case when @@language = 'V' then ten_vv else ten_vv2 end from dmvv where ma_vv = @ma)
  end
select 'this._header = ''' + replace(replace(isnull(@header, ''), '\', '\\'), '''', '\''') + '''; this._Name = ''' + replace(replace(isnull(@name, ''), '\', '\\'), '''', '\''') + '''; this._dTo = ''' + convert(char(10), @den_ngay, 103) + ''';this._queryFilterString = ''' + replace(replace(@@queryString, '\', '\\'), '''', '\''') + ''';init$GridQuery$(this);' as message
return




    &XMLWhenReportLoading;
    &XMLWhenReportClosing;




      &DeclareCommandFilter;



        &QueryString;

declare @queryWhereClause nvarchar(4000), @queryFormClause nvarchar(4000)
select @queryFormClause = 'left join dmkh b with(nolock, index(pk_dmkh)) on a.ma_kh = b.ma_kh left join dmct c with(nolock) on a.ma_ct = c.ma_ct'
select @queryWhereClause =
  case
    when @bc_theo = 1 then 'a.tk = ''' + replace(@ma, '''', '''''') + ''''
    when @bc_theo = 2 then 'a.ma_phi = ''' + replace(@ma, '''', '''''') + ''''
    when @bc_theo = 3 then 'a.ma_dvcs = ''' + replace(@ma, '''', '''''') + ''''
    when @bc_theo = 4 then 'a.ma_bp = ''' + replace(@ma, '''', '''''') + ''''
    when @bc_theo = 5 then 'a.ma_vv = ''' + replace(@ma, '''', '''''') + ''''
  end

if @nh_theo1 <> 0 begin
  select @queryWhereClause =
    case
      when @nh_theo1 = 1 then @queryWhereClause + case when @bc_theo = 1 then '' else ' and a.tk = ''' + replace(@group1By, '''', '''''') + '''' end
      when @nh_theo1 = 2 then @queryWhereClause + case when @bc_theo = 2 then '' else ' and a.ma_phi = ''' + replace(@group1By, '''', '''''') + '''' end
      when @nh_theo1 = 3 then @queryWhereClause + case when @bc_theo = 3 then '' else ' and a.ma_dvcs = ''' + replace(@group1By, '''', '''''') + '''' end
      when @nh_theo1 = 4 then @queryWhereClause + case when @bc_theo = 4 then '' else ' and a.ma_bp = ''' + replace(@group1By, '''', '''''') + '''' end
      when @nh_theo1 = 5 then @queryWhereClause + case when @bc_theo = 5 then '' else ' and a.ma_vv = ''' + replace(@group1By, '''', '''''') + '''' end
    end
end

if @nh_theo2 <> 0 begin
  select @queryWhereClause =
    case
      when @nh_theo2 = 1 then @queryWhereClause + case when @bc_theo = 1 or @nh_theo1 = 1 then '' else ' and a.tk = ''' + replace(@group2By, '''', '''''') + '''' end
      when @nh_theo2 = 2 then @queryWhereClause + case when @bc_theo = 2 or @nh_theo1 = 2 then '' else ' and a.ma_phi = ''' + replace(@group2By, '''', '''''') + '''' end
      when @nh_theo2 = 3 then @queryWhereClause + case when @bc_theo = 3 or @nh_theo1 = 3 then '' else ' and a.ma_dvcs = ''' + replace(@group2By, '''', '''''') + '''' end
      when @nh_theo2 = 4 then @queryWhereClause + case when @bc_theo = 4 or @nh_theo1 = 4 then '' else ' and a.ma_bp = ''' + replace(@group2By, '''', '''''') + '''' end
      when @nh_theo2 = 5 then @queryWhereClause + case when @bc_theo = 5 or @nh_theo1 = 5 then '' else ' and a.ma_vv = ''' + replace(@group2By, '''', '''''') + '''' end
    end
end

if not(@bc_theo = 2 or @nh_theo1 = 2 or @nh_theo2 = 2) begin
  if @nh_phi1 + @nh_phi2 + @nh_phi3 <> '' select @queryFormClause = @queryFormClause + ' left join dmphi c with(nolock) on a.ma_phi = c.ma_phi'
  if @nh_phi1 <> '' select @queryWhereClause = @queryWhereClause + ' and c.nh_phi1 like ''' + replace(@nh_phi1, '''', '''''') + '%'''
  if @nh_phi2 <> '' select @queryWhereClause = @queryWhereClause + ' and c.nh_phi2 like ''' + replace(@nh_phi2, '''', '''''') + '%'''
  if @nh_phi3 <> '' select @queryWhereClause = @queryWhereClause + ' and c.nh_phi3 like ''' + replace(@nh_phi3, '''', '''''') + '%'''
end

if @ds_tk <> '' and @bc_theo <> 1 and @nh_theo1 <> 1 and @nh_theo2 <> 1 select @queryWhereClause = @queryWhereClause + ' and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk', 'inlist', @ds_tk)

select @queryWhereClause = @queryWhereClause +
  case
    when @loai = 1 then ' and (ps_no + ps_no_nt <> 0' + case when @ds_tk_gt = '' then ')' else ' or (ps_co + ps_co_nt <> 0 and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk_du', 'notinlist', @ds_tk_gt) + '))' end
    when @loai = 2 then ' and (ps_co + ps_co_nt <> 0' + case when @ds_tk_gt = '' then ')' else ' or (ps_no + ps_no_nt <> 0 and ' + dbo.FastBusiness$Function$System$GetAccountFilter('a.tk_du', 'notinlist', @ds_tk_gt) + '))' end
  end

&FilterInitialize;&FilterQuery;
exec FastBusiness$Report$GLDetail @@refresh, @@pageIndex, @@pageCount, @@lastPage, @@lastCount, @@firstItem, @@lastItem, @@textExternal, @queryFormClause, @queryWhereClause, @tu_ngay, @den_ngay, @ma_dvcs, @@admin, @@userID, @@aggregation







      &JavascriptReportInit;
      /* <flatten type="Javascript"> */
function init$GridQuery$(g) {
  var a = g._queryFilterString.split(String.fromCharCode(253));
  g._alterTitle = [null, [['%h', g._header, true], ['%c', a[0], true], ['%s', g._Name, true], ['%d1', formatDateView(a[3]), true], ['%d2', g._dTo, true]]];
  g._hiddenFields = [
    {Fields: 'ps_no_nt, ps_co_nt', Value: (a[8] == '10')},
    {Fields: 'tk', Value: (a[6] == '1')},
    {Fields: 'ma_vv', Value: (a[6] == '5')}
  ];
}
/* </flatten> */



